import React from 'react';
import { ALL_ROOMS } from '../data/roomsData';

const RoomList = ({ floor, onSelectRoom }) => {
    // Фильтруем номера: оставляем только те, что принадлежат выбранному этажу
    const roomsOnFloor = ALL_ROOMS.filter(room => room.floor === floor);

    return (
        <div className="page-content">
            <h2 className="page-title">{floor} Этаж</h2>
            <div className="room-grid">
                {roomsOnFloor.map(room => (
                    <div
                        key={room.id}
                        className={`room-box status-${room.status}`}
                        onClick={() => onSelectRoom(room)}
                    >
                        {room.id}
                    </div>
                ))}
            </div>
        </div>
    );
};

export default RoomList;
